We start with a diagram:

[asy]
pair D,EE,F;

EE = (0,0);
F = (8,0);
D = (0,8*Tan(65));
draw(D--EE--F--D);
draw(rightanglemark(F,EE,D,18));
label("$E$",EE,SW);
label("$F$",F,SE);
label("$D$",D,N);
label("$9$",F/2,S);
[/asy]

